// export default PriceAnalytics;
import React, { useEffect, useState } from "react";
import axios from "axios";
import {
  BarChart,
  Bar,
  CartesianGrid,
  XAxis,
  YAxis,
  Tooltip,
  Legend,
  ResponsiveContainer,
} from "recharts";
import "./PriceAnalytics.css";

const API_URL = "http://localhost:7000/api/products";

export default function PriceAnalytics() {
  const [products, setProducts] = useState([]);
  const [filteredData, setFilteredData] = useState([]);
  const [categories, setCategories] = useState([]);
  const [selectedCategory, setSelectedCategory] = useState("All");
  const [fromDate, setFromDate] = useState("");
  const [toDate, setToDate] = useState("");

  // Fetch data
  const fetchData = async () => {
    try {
      const res = await axios.get(API_URL);
      const data = Array.isArray(res.data)
        ? res.data
        : res.data.data || [];
      setProducts(data);
      setFilteredData(data);

      const uniqueCategories = [
        ...new Set(data.map((item) => item.category)),
      ];
      setCategories(uniqueCategories);
    } catch (error) {
      console.error("Error fetching data:", error);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  // Filter by category + date range
  const handleFilter = () => {
    let filtered = products;

    if (selectedCategory !== "All") {
      filtered = filtered.filter(
        (item) => item.category === selectedCategory
      );
    }

    if (fromDate && toDate) {
      filtered = filtered.filter((item) => {
        const created = new Date(item.createdAt);
        return created >= new Date(fromDate) && created <= new Date(toDate);
      });
    }

    setFilteredData(filtered);
  };

  // Category-wise average price data for chart
  const categoryData = categories.map((cat) => {
    const catProducts = products.filter((p) => p.category === cat);
    const avgPrice =
      catProducts.reduce((sum, p) => sum + p.price, 0) / catProducts.length || 0;
    const avgStock =
      catProducts.reduce((sum, p) => sum + p.stock, 0) / catProducts.length || 0;
    return {
      category: cat,
      avgPrice,
      avgStock,
    };
  });

  return (
    <div className="analytics-container">
      <h2 className="analytics-title">📊 Price & Stock Analytics Dashboard</h2>

      {/* Filter Controls */}
      <div className="filter-box">
        <label>From:</label>
        <input
          type="date"
          value={fromDate}
          onChange={(e) => setFromDate(e.target.value)}
        />

        <label>To:</label>
        <input
          type="date"
          value={toDate}
          onChange={(e) => setToDate(e.target.value)}
        />

        <label>Category:</label>
        <select
          value={selectedCategory}
          onChange={(e) => setSelectedCategory(e.target.value)}
        >
          <option value="All">All</option>
          {categories.map((cat, idx) => (
            <option key={idx} value={cat}>
              {cat}
            </option>
          ))}
        </select>

        <button onClick={handleFilter}>Apply Filters</button>
      </div>

      {/* Product-wise Bar Graph */}
      <div className="chart-section">
        <h3>📈 Product-wise Price & Stock</h3>
        {filteredData.length > 0 ? (
          <ResponsiveContainer width="100%" height={400}>
            <BarChart data={filteredData}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="name" />
              <YAxis />
              <Tooltip />
              <Legend />
              <Bar dataKey="price" fill="#82ca9d" name="Price (₹)" />
              <Bar dataKey="stock" fill="#8884d8" name="Stock" />
            </BarChart>
          </ResponsiveContainer>
        ) : (
          <p className="no-data">No data available for selected filters</p>
        )}
      </div>

      {/* Category-wise Average Chart */}
      <div className="chart-section">
        <h3>📊 Category-wise Average Price & Stock</h3>
        <ResponsiveContainer width="100%" height={400}>
          <BarChart data={categoryData}>
            <CartesianGrid strokeDasharray="3 3" />
            <XAxis dataKey="category" />
            <YAxis />
            <Tooltip />
            <Legend />
            <Bar dataKey="avgPrice" fill="#ffc658" name="Avg Price (₹)" />
            <Bar dataKey="avgStock" fill="#0088fe" name="Avg Stock" />
          </BarChart>
        </ResponsiveContainer>
      </div>

      {/* Product Table */}
      <div className="product-table">
        <h3>🧾 Filtered Products</h3>
        {filteredData.length > 0 ? (
          <table>
            <thead>
              <tr>
                <th>#</th>
                <th>Product</th>
                <th>Category</th>
                <th>Price (₹)</th>
                <th>Stock</th>
                <th>Date</th>
              </tr>
            </thead>
            <tbody>
              {filteredData.map((item, i) => (
                <tr key={item._id}>
                  <td>{i + 1}</td>
                  <td>{item.name}</td>
                  <td>{item.category}</td>
                  <td>{item.price}</td>
                  <td>{item.stock}</td>
                  <td>{new Date(item.createdAt).toLocaleDateString()}</td>
                </tr>
              ))}
            </tbody>
          </table>
        ) : (
          <p style={{ textAlign: "center" }}>No products found</p>
        )}
      </div>
    </div>
  );
}
